// pipeline-topics.js - programmatic SEO dataset for pipeline, deals, opportunity
// management, and forecasting. Compact GUIDES + TERMS arrays expanded by .map()
// into full page entries. NO em-dash / en-dash. ASCII hyphen only.
// type 'guide' = how-tos / playbooks (steps). type 'glossary' = definitions / metrics.
const PUB = '2026-07-10';

// Clamp a meta description to 155 chars on a word boundary (SEO limit).
const clampDesc = (s) => {
  if (!s || s.length <= 155) return s;
  let t = s.slice(0, 155);
  const sp = t.lastIndexOf(' ');
  if (sp > 0) t = t.slice(0, sp);
  return t.replace(/[\s,;:.\-]+$/, '');
};

